+    fn styled_line_spans(
+        &self,
+        pane: PaneFocus,
+        row: usize,
+        line: &str,
+    ) -> Vec<Span<'static>> {
+        let Some(selection) = self
+            .visual_selection
+            .as_ref()
+            .filter(|selection| selection.pane == pane)
+        else {
+            return vec![Span::raw(line.to_string())];
+        };
+        let Some((start, end)) = selected_columns_for_line(selection, row, line, false) else {
+            return vec![Span::raw(line.to_string())];
+        };
+        let line_len = line.chars().count();
+        let start = start.min(line_len);
+        let end = end.min(line_len);
+        if start >= end {
+            return vec![Span::raw(line.to_string())];
+        }
+
+        let mut spans = Vec::new();
+        let prefix = slice_chars(line, 0, start);
+        if !prefix.is_empty() {
+            spans.push(Span::raw(prefix));
+        }
+        spans.push(Span::styled(
+            slice_chars(line, start, end),
+            Style::default().add_modifier(Modifier::REVERSED),
+        ));
+        let suffix = slice_chars(line, end, line_len);
+        if !suffix.is_empty() {
+            spans.push(Span::raw(suffix));
+        }
+        spans
+    }

