+    fn visual_origin(&self) -> TextPosition {
+        match self.focus {
+            PaneFocus::Left => TextPosition {
+                row: self.control_selected,
+                column: 0,
+            },
+            PaneFocus::Right => self.right_visual_origin.get(),
+        }
