+    fn start_visual_selection(&mut self, kind: VisualKind) {
+        if self.mode != UiMode::Command {
+            return;
+        }
+        let origin = self.visual_origin();
+        self.visual_selection = Some(VisualSelection {
+            pane: self.focus,
+            kind,
+            anchor: origin,
+            cursor: origin,
+        });
+    }
+
+    fn clear_visual_selection(&mut self) {
+        self.visual_selection = None;
+    }
+
+    fn switch_visual_kind(&mut self, kind: VisualKind) {
+        if let Some(selection) = self.visual_selection.as_mut() {
+            selection.kind = kind;
+        } else {
+            self.start_visual_selection(kind);
+        }
+    }
+
+    fn handle_visual_key(&mut self, key: UiKey) -> Vec<UiAction> {
+        match key {
+            UiKey::Esc => {
+                self.clear_visual_selection();
+            }
+            UiKey::Char('v') => {
+                if self
+                    .visual_selection
+                    .as_ref()
+                    .is_some_and(|selection| selection.kind == VisualKind::Character)
+                {
+                    self.clear_visual_selection();
+                } else {
+                    self.switch_visual_kind(VisualKind::Character);
+                }
+            }
+            UiKey::Char('V') => self.switch_visual_kind(VisualKind::Line),
+            UiKey::Char('h') | UiKey::Left => self.move_visual_cursor(0, -1),
+            UiKey::Char('j') | UiKey::Down => self.move_visual_cursor(1, 0),
+            UiKey::Char('k') | UiKey::Up => self.move_visual_cursor(-1, 0),
+            UiKey::Char('l') | UiKey::Right => self.move_visual_cursor(0, 1),
+            UiKey::Char('y') | UiKey::Char('Y') => self.clear_visual_selection(),
+            _ => {}
+        }
+        Vec::new()
+    }
+
+    fn move_visual_cursor(&mut self, row_delta: isize, column_delta: isize) {
+        let left_lines = self
+            .visual_selection
+            .as_ref()
+            .filter(|selection| selection.pane == PaneFocus::Left)
+            .map(|_| {
+                self.left_pane_rows()
+                    .into_iter()
+                    .map(|row| row.text)
+                    .collect::<Vec<_>>()
+            });
+        let Some(selection) = self.visual_selection.as_mut() else {
+            return;
+        };
+        selection.cursor.row = apply_delta(selection.cursor.row, row_delta);
+        selection.cursor.column = apply_delta(selection.cursor.column, column_delta);
+
+        if let Some(lines) = left_lines.as_ref() {
+            if lines.is_empty() {
+                selection.cursor = TextPosition::default();
+                return;
+            }
+            selection.cursor.row = selection.cursor.row.min(lines.len() - 1);
+            let line_len = lines[selection.cursor.row].chars().count();
+            selection.cursor.column = selection.cursor.column.min(line_len);
+        }
+    }
+
+    fn visual_lines_for_selection(
+        &self,
+        selection: &VisualSelection,
+        right_content: &str,
+    ) -> Vec<String> {
+        match selection.pane {
+            PaneFocus::Left => self
+                .left_pane_rows()
+                .into_iter()
+                .map(|row| row.text)
+                .collect(),
+            PaneFocus::Right => content_lines(&self.visible_right_content(right_content)),
+        }
+    }
+
+    fn visual_cursor_position(
+        &self,
+        selection: &VisualSelection,
+        right_content: &str,
+    ) -> (u16, u16) {
+        match selection.pane {
+            PaneFocus::Left => {
+                let row = selection.cursor.row.saturating_add(2);
+                let column = selection.cursor.column.saturating_add(2);
+                (
+                    row.min(usize::from(u16::MAX)) as u16,
+                    column.min(usize::from(u16::MAX)) as u16,
+                )
+            }
+            PaneFocus::Right => self.right_visual_cursor_position(right_content, selection.cursor),
+        }
+    }
+
+    fn right_visual_cursor_position(
+        &self,
+        right_content: &str,
+        cursor: TextPosition,
+    ) -> (u16, u16) {
+        let layout = self.layout();
+        let inner_width = layout.right_width.saturating_sub(2).max(1);
+        let lines = content_lines(right_content);
+        let row_index = cursor.row.min(lines.len().saturating_sub(1));
+        let line = lines.get(row_index).map(String::as_str).unwrap_or("");
+        let column = cursor.column.min(line.chars().count());
+        let previous_rows = lines[..row_index]
+            .iter()
+            .map(|line| visual_row_count(line, inner_width))
+            .sum::<usize>();
+        let row = 2_usize
+            .saturating_add(previous_rows)
+            .saturating_add(column / usize::from(inner_width));
+        let column = usize::from(layout.left_width)
+            .saturating_add(2)
+            .saturating_add(column % usize::from(inner_width));
+        (
+            row.min(usize::from(u16::MAX)) as u16,
+            column.min(usize::from(u16::MAX)) as u16,
+        )
+    }

