+    if lines.is_empty() {
+        return String::new();
+    }
+    let anchor = clamp_position(selection.anchor, lines);
+    let cursor = clamp_position(selection.cursor, lines);
+    let start_row = anchor.row.min(cursor.row);
+    let end_row = anchor.row.max(cursor.row);
+    let keep_empty_rows = force_linewise || matches!(selection.kind, VisualKind::Line | VisualKind::Block);
+
+    let mut selected = Vec::new();
+    for row in start_row..=end_row {
+        let line = &lines[row];
+        if let Some((start, end)) = selected_columns_for_line(selection, row, line, force_linewise)
+        {
+            selected.push(slice_chars(line, start, end));
+        } else if keep_empty_rows {
+            selected.push(String::new());
+        }
+    }
+    selected.join("\n")
+}
+
+fn selected_columns_for_line(
+    selection: &VisualSelection,
+    row: usize,
+    line: &str,
+    force_linewise: bool,
+) -> Option<(usize, usize)> {
+    let line_len = line.chars().count();
+    let anchor = selection.anchor;
+    let cursor = selection.cursor;
+    let start_row = anchor.row.min(cursor.row);
+    let end_row = anchor.row.max(cursor.row);
+    if row < start_row || row > end_row {
+        return None;
+    }
+
+    let kind = if force_linewise {
+        VisualKind::Line
+    } else {
+        selection.kind
+    };
+    match kind {
+        VisualKind::Line => Some((0, line_len)),
+        VisualKind::Block => {
+            let start = anchor.column.min(cursor.column).min(line_len);
+            let end = anchor
+                .column
+                .max(cursor.column)
+                .saturating_add(1)
+                .min(line_len);
+            Some((start, end))
+        }
+        VisualKind::Character => {
+            let ordered = if (anchor.row, anchor.column) <= (cursor.row, cursor.column) {
+                (anchor, cursor)
+            } else {
+                (cursor, anchor)
+            };
+            if ordered.0.row == ordered.1.row {
+                let start = ordered.0.column.min(line_len);
+                let end = ordered.1.column.saturating_add(1).min(line_len);
+                Some((start, end))
+            } else if row == ordered.0.row {
+                Some((ordered.0.column.min(line_len), line_len))
+            } else if row == ordered.1.row {
+                Some((0, ordered.1.column.saturating_add(1).min(line_len)))
+            } else {
+                Some((0, line_len))
+            }
+        }
+    }
+}
+
+fn clamp_position(position: TextPosition, lines: &[String]) -> TextPosition {
+    if lines.is_empty() {
+        return TextPosition::default();
+    }
+    let row = position.row.min(lines.len() - 1);
+    TextPosition {
+        row,
+        column: position.column.min(lines[row].chars().count()),
+    }
+}
+
+fn slice_chars(text: &str, start: usize, end: usize) -> String {
+    text.chars()
+        .skip(start)
+        .take(end.saturating_sub(start))
+        .collect()
+}
+
+fn osc52_copy_sequence(text: &str) -> String {
+    format!("\u{1b}]52;c;{}\u{7}", base64_encode(text.as_bytes()))
+}
+
+fn base64_encode(bytes: &[u8]) -> String {
+    const TABLE: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
+    let mut encoded = String::new();
+    for chunk in bytes.chunks(3) {
+        let first = chunk[0];
+        let second = *chunk.get(1).unwrap_or(&0);
+        let third = *chunk.get(2).unwrap_or(&0);
+        encoded.push(TABLE[(first >> 2) as usize] as char);
+        encoded.push(TABLE[(((first & 0b0000_0011) << 4) | (second >> 4)) as usize] as char);
+        if chunk.len() > 1 {
+            encoded.push(TABLE[(((second & 0b0000_1111) << 2) | (third >> 6)) as usize] as char);
+        } else {
+            encoded.push('=');
+        }
+        if chunk.len() > 2 {
+            encoded.push(TABLE[(third & 0b0011_1111) as usize] as char);
+        } else {
+            encoded.push('=');
+        }
+    }
+    encoded
+}
